  centerArm=(4.5+MaximumRadius)/2;

  armLength=(MaximumRadius-4.5)+HoleSize;
    armW=HoleSize*arm_w_m;



  holeDelta=(HolesPerArm>1) ? (MaximumRadius-MinimumRadius)/(HolesPerArm-1) : 0;

  cornerR=3.0*R_center/ArmNumber;


  rotate(gamma,[0,0,1]) {
    difference() {

      union() {

        translate([0,centerArm-HoleSize/2,Thickness/2])
          cube([armW,armLength+HoleSize,Thickness],center=true);

        translate([0,MaximumRadius+HoleSize/2,Thickness/2])
          cylinder(r=armW/2,h=Thickness,center=true);

        translate([armW/2,(armW/2)/tand(dgamma/2),Thickness/2])
          linear_extrude(height=Thickness,twist=0,center=true)
            polygon(points=[[0,0],[0,cornerR/tand(dgamma/2)],[cornerR*sind(dgamma)/tand(dgamma/2),cornerR*cosd(dgamma)/tand(dgamma/2)]]);
