module pianoHingeNubs(d,h) {
    unit = h/6;

  union() {
    cylinder(h=unit, r=d/2);
    translate([0,0,unit]) cylinder(h=unit, r1=d/2, r2=d/4);
    translate([0,0,4*unit]) cylinder(h=unit, r1=d/4, r2=d/2);
    translate([0,0,5*unit]) cylinder(h=unit, r=d/2);
  }
}

module pianoHingeCore(gap,d,h) {
    unit = h/6;

    difference() {

        translate([0,0,unit+gap]) cylinder(h=4*unit-2*gap, r=d/2);


        translate([0,0,unit+gap]) cylinder(h=unit, r1=d/2, r2=d/4);
        translate([0,0,4*unit-gap]) cylinder(h=unit, r1=d/4, r2=d/2);
    }
}

module pianoHingeBridge(bridge,gap,d,h,angle=180) {
    bridgeLength = bridge[0]+d/2;
    unit = h/6;

    difference() {
        union() {

            translate([unit+gap,bridgeLength,d/2])
            rotate([180-angle,0,0])
            translate([0,0,-d/2])
            cube([4*unit-2*gap,bridgeLength,bridge[1]]);

            translate([0,0,0])
            cube([unit,bridgeLength,bridge[1]]);
            translate([5*unit,0,0])
            cube([unit,bridgeLength,bridge[1]]);
        }


        translate(
            [0,d/2,d/2]
            +[0,bridge[0],0]
        )
        rotate([0,90,0])
        cylinder(h=width,d=d);
    }
}

module externalPianoHinge(width,diameter,bridge=[0,0],bridgeAngle=180) {
    gap = .4;

    segmentWidth = 2*diameter;
    hinges = round(width/segmentWidth) < 1 ? 1 : round(width/segmentWidth);
    widthScaling = 1 + (width - hinges*segmentWidth) / (hinges*segmentWidth);
    scaledWidth = segmentWidth*widthScaling;


    for(i = [0:1:hinges-1]) {
        translate([i*scaledWidth,0,0])
        union() {
            if(bridge != [0,0]) pianoHingeBridge(bridge,gap,diameter,scaledWidth,bridgeAngle);

            translate([0,bridge[0]+diameter/2,diameter/2])
            rotate([0,90,0]) {
                pianoHingeNubs(diameter,scaledWidth);
                pianoHingeCore(gap,diameter,scaledWidth);
            }
        }
    }
}

module pianoHingeBridgeCuts(bridge,gap,d,h,mirrorBridge=false) {
    bridgeLength = bridge[0]+d/2;
    unit = h/6;

    coreTranslation = mirrorBridge ? [unit,0,0] : [unit,bridgeLength,0];
    leftNubTranslation = mirrorBridge ? [0,bridgeLength,0] : [0,0,0];
    rightNubTranslation = mirrorBridge ? [5*unit-gap,bridgeLength,0] : [5*unit-gap,0,0];

    union() {

        translate(coreTranslation)
        cube([4*unit,bridgeLength,bridge[1]]);

        translate(leftNubTranslation)
        cube([unit+gap,bridgeLength,bridge[1]]);
        translate(rightNubTranslation)
        cube([unit+gap+.01,bridgeLength,bridge[1]]);



        translate(
            [0,d/2,d/2]
            +[0,bridge[0],0]
        )
        rotate([0,90,0])
        cylinder(h=h,d=d);
    }
}

module pianoHinge(translation,width,diameter,bridge=[0,0],mirrorBridge=false) {
    gap = .4;

    segmentWidth = 2*diameter;
    hinges = round(width/segmentWidth) < 1 ? 1 : round(width/segmentWidth);
    widthScaling = 1 + (width - hinges*segmentWidth) / (hinges*segmentWidth);
    scaledWidth = segmentWidth*widthScaling;

    if(bridge != [0,0]) {
        difference() {
            children();

            for(i = [0:1:hinges-1]) {
                translate(translation+[i*scaledWidth,0,0])
                pianoHingeBridgeCuts(bridge,gap,diameter,scaledWidth,mirrorBridge);
            }
        }
    }


    for(i = [0:1:hinges-1]) {
        translate([i*scaledWidth,0,0])
        union() {

            translate(translation+[0,bridge[0]+diameter/2,diameter/2])
            rotate([0,90,0]) {
                pianoHingeNubs(diameter,scaledWidth);
                pianoHingeCore(gap,diameter,scaledWidth);
            }
        }
    }
}

